import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart, Store, Radar, BellRing, Search, Loader2 } from 'lucide-react';
import { api } from '../services/api'; 
import { useCart } from '../context/CartContext'; 
import { useAuth } from '../context/AuthContext';
import { calcularDistancia } from '../utils/radarService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const { cart, addToCart, count, clearCart } = useCart(); 
  const { user } = useAuth(); // Usamos el usuario del contexto global
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [verCarrito, setVerCarrito] = useState(false);
  const [miUbicacion, setMiUbicacion] = useState(null);
  const [radarActivo, setRadarActivo] = useState(false);
  const [notificaciones, setNotificaciones] = useState([]);
  const [favoritos, setFavoritos] = useState([]); 
  const [loading, setLoading] = useState(true);

  const searchTimer = useRef(null);
  const currentUserId = user?.id;

  // --- APRENDIZAJE DE INTERESES ---
  const registrarInteres = useCallback((terminos) => {
    if (!currentUserId) return;
    const palabras = Array.isArray(terminos) ? terminos : [terminos];
    setFavoritos(prev => {
      let nuevosFavs = [...prev];
      palabras.forEach(p => {
        if (typeof p !== 'string') return;
        const limpia = p.toLowerCase().split(' ')[0].replace(/[^a-z]/g, '');
        if (limpia.length > 2 && !nuevosFavs.includes(limpia)) {
          nuevosFavs.push(limpia);
        }
      });
      const sliceFinal = nuevosFavs.slice(-15);
      localStorage.setItem(`favs-${currentUserId}`, JSON.stringify(sliceFinal));
      return sliceFinal;
    });
  }, [currentUserId]);

  // --- CARGA DE DATOS ---
  const cargarDatosDesdeDB = async () => {
    setLoading(true);
    try {
      const todasLasOfertas = await api.getTodasLasOfertas();
      
      const agrupado = todasLasOfertas.reduce((acc, oferta) => {
        const local = oferta.local;
        if (!local) return acc;
        if (!acc[local.nombre]) {
          acc[local.nombre] = { 
            info: { 
                id: local._id, 
                nombre: local.nombre, 
                direccion: local.direccion,
                lng: local.location?.coordinates[0],
                lat: local.location?.coordinates[1]
            }, 
            ofertas: [] 
          };
        }
        acc[local.nombre].ofertas.push(oferta);
        return acc;
      }, {});
      
      setOfertasPorLocal(agrupado);

      const resPedidos = await fetch(`http://localhost:5000/api/pedidos/cliente/${currentUserId}`);
      if(resPedidos.ok) {
          const dataPedidos = await resPedidos.json();
          setPedidos(dataPedidos);
      }
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (currentUserId) {
      cargarDatosDesdeDB();
      const guardados = JSON.parse(localStorage.getItem(`favs-${currentUserId}`) || "[]");
      setFavoritos(guardados);
    }
  }, [currentUserId]);

  // --- LÓGICA DE RADAR ---
  useEffect(() => {
    let watchId = null;
    if (radarActivo && navigator.geolocation) {
      watchId = navigator.geolocation.watchPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        setMiUbicacion({ lat: latitude, lng: longitude });
        
        const encontradas = [];
        Object.values(ofertasPorLocal).forEach(grupo => {
          grupo.ofertas.forEach(o => {
            const coincide = favoritos.some(fav => o.producto.toLowerCase().includes(fav));
            if (coincide && grupo.info.lat && grupo.info.lng) {
              const d = calcularDistancia(latitude, longitude, grupo.info.lat, grupo.info.lng);
              if (d <= 1.5) { // Aumentado a 1.5km para mejor rango
                  encontradas.push({ ...o, dist: d.toFixed(2), localNombre: grupo.info.nombre });
              }
            }
          });
        });
        setNotificaciones(encontradas);
      }, (err) => console.error(err), { enableHighAccuracy: true });
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [radarActivo, ofertasPorLocal, favoritos]);

  const handlePago = async (total) => {
    const pedidoData = {
      cliente: currentUserId,
      items: cart.map(item => ({
        producto: item.producto,
        precio: item.precio,
        cantidad: 1,
        localId: item.local._id || item.local
      })),
      total,
      puntoEntrega: miUbicacion
    };

    try {
        const res = await fetch('http://localhost:5000/api/pedidos', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(pedidoData)
        });
        if(res.ok) {
            alert("¡Pedido enviado con éxito!");
            clearCart();
            await cargarDatosDesdeDB(); 
            setVerCarrito(false);
            setTab('proceso');
        }
    } catch (e) {
        alert("Error al conectar con el servidor");
    }
  };

  if (loading) return (
    <div style={loaderStyle}>
      <Loader2 size={40} className="spinner" />
      <p>Buscando las mejores ofertas para ti...</p>
      <style>{`.spinner { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );

  return (
    <div style={layout}>
      {/* NAVEGACIÓN DE PESTAÑAS (Debajo del Header) */}
      <div style={tabContainer}>
        <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? tabActive : tabBtn}>
          <ShoppingBag size={18} /> Tienda
        </button>
        <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? tabActive : tabBtn}>
          <ShoppingCart size={18} /> Carrito ({count})
        </button>
        <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? tabActive : tabBtn}>
          <Clock size={18} /> En Proceso
        </button>
        <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? tabActive : tabBtn}>
          <CheckCircle size={18} /> Mis Compras
        </button>
      </div>

      <main style={mainContent}>
        {tab === 'tienda' && !verCarrito && (
          <div style={{ maxWidth: '1000px', margin: '0 auto' }}>
            
            {/* SECCIÓN RADAR */}
            <div style={radarCard(radarActivo)}>
              <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
                <div style={radarCircle(radarActivo)}><Radar size={24} color={radarActivo ? "#fff" : "#e67e22"} /></div>
                <div style={{flex: 1}}>
                  <h3 style={{margin: 0, fontSize: '1.1rem'}}>Radar de Ahorro Inteligente</h3>
                  <p style={{margin: 0, fontSize: '0.85rem', opacity: 0.8}}>
                    {radarActivo ? `Vigilando ofertas de: ${favoritos.slice(0, 5).join(', ')}...` : 'Activa el radar para recibir avisos cuando pases cerca de una oferta.'}
                  </p>
                </div>
                <button onClick={() => setRadarActivo(!radarActivo)} style={btnRadar(radarActivo)}>
                  {radarActivo ? 'DETENER RADAR' : 'ACTIVAR AHORRO'}
                </button>
              </div>
              
              {radarActivo && notificaciones.length > 0 && (
                <div style={notifBox}>
                  {notificaciones.map(n => (
                    <div key={n._id} style={notifItem}>
                      <BellRing size={18} color="#e67e22" />
                      <div style={{flex: 1}}>
                        <div style={{fontSize: '0.85rem', fontWeight: 'bold'}}>¡{n.producto} cerca tuyo!</div>
                        <div style={{fontSize: '0.75rem'}}>{n.localNombre} • A {n.dist} km</div>
                      </div>
                      <button style={btnIr} onClick={() => addToCart(n)}>Agregar $ {n.precio}</button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* BUSCADOR */}
            <div style={searchBox}>
              <Search size={20} color="#94a3b8" />
              <input 
                style={input} 
                placeholder="¿Qué se te antoja hoy? (pizza, cerveza, helado...)" 
                value={busqueda} 
                onChange={(e) => {
                    setBusqueda(e.target.value);
                    if (searchTimer.current) clearTimeout(searchTimer.current);
                    searchTimer.current = setTimeout(() => registrarInteres(e.target.value), 1500);
                }} 
              />
            </div>

            {/* LISTADO DE TIENDAS */}
            {Object.keys(ofertasPorLocal).length > 0 ? Object.keys(ofertasPorLocal).map(nombreLocal => {
              const local = ofertasPorLocal[nombreLocal].info;
              const dist = miUbicacion && local.lat ? calcularDistancia(miUbicacion.lat, miUbicacion.lng, local.lat, local.lng).toFixed(1) : "--";
              
              return (
                <div key={nombreLocal} style={tiendaSeccion}>
                  <div style={headerTienda}>
                    <div style={avatarTienda}><Store size={22} color="#e67e22" /></div>
                    <div>
                      <h3 style={{margin: 0, fontSize: '1.1rem'}}>{nombreLocal}</h3>
                      <div style={metaTienda}>
                        <span><MapPin size={12} /> {local.direccion}</span>
                        <span style={{color: '#27ae60', fontWeight: 'bold'}}> • {dist} km de ti</span>
                      </div>
                    </div>
                  </div>
                  <div style={scrollRow}>
                    {ofertasPorLocal[nombreLocal].ofertas
                      .filter(o => o.producto.toLowerCase().includes(busqueda.toLowerCase()))
                      .map(o => (
                        <div key={o._id} style={cardShop}>
                          <img src={o.imagenUrl || "https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=400"} style={imgShop} alt={o.producto} />
                          <div style={{padding: '15px'}}>
                            <h4 style={{margin: '0 0 8px 0', fontSize: '0.95rem', height: '40px', overflow: 'hidden'}}>{o.producto}</h4>
                            <div style={pPrecio}>${o.precio}</div>
                            <button style={btnAdd} onClick={() => addToCart(o)}>
                                <ShoppingCart size={16} /> Agregar
                            </button>
                          </div>
                        </div>
                    ))}
                  </div>
                </div>
              );
            }) : <p style={{textAlign:'center', color:'#64748b'}}>No hay ofertas disponibles en este momento.</p>}
          </div>
        )}

        {verCarrito && (
          <div style={cartContainerStyle}>
            <Carrito onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centerCont}>
            <h2 style={{display:'flex', alignItems:'center', gap:'10px', color: '#1e293b'}}><Clock color="#e67e22"/> Pedidos en camino</h2>
            {pedidos.filter(p => p.estado === 'proceso').length === 0 ? (
                <div style={emptyState}>
                  <ShoppingBag size={48} color="#cbd5e1" />
                  <p>No tienes pedidos activos actualmente.</p>
                </div>
            ) : (
                pedidos.filter(p => p.estado === 'proceso').map(p => (
                    <SeguimientoPedido key={p._id} pedido={p} />
                ))
            )}
          </div>
        )}

        {tab === 'historial' && (
          <div style={centerCont}>
             <h2 style={{display:'flex', alignItems:'center', gap:'10px', color: '#1e293b'}}><CheckCircle color="#27ae60"/> Historial de compras</h2>
             {pedidos.filter(p => p.estado === 'completado').length === 0 ? (
               <p style={{color:'#64748b', textAlign:'center'}}>Aún no has realizado compras.</p>
             ) : (
               pedidos.filter(p => p.estado === 'completado').map(p => (
                 <div key={p._id} style={historialCard}>
                   <div>
                     <div style={{fontWeight: 'bold', color: '#1e293b'}}>Compra en {p.local?.nombre || 'Local'}</div>
                     <small style={{color:'#94a3b8'}}>{new Date(p.createdAt).toLocaleDateString()}</small>
                   </div>
                   <div style={{textAlign: 'right'}}>
                     <div style={{color: '#e67e22', fontWeight:'bold'}}>${p.total}</div>
                     <small style={{color:'#27ae60', fontWeight:'600'}}>Entregado</small>
                   </div>
                 </div>
               ))
             )}
          </div>
        )}
      </main>
    </div>
  );
};

