const imgShop = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight:'600', borderRadius: '0 0 15px 15px' };
